import (
	"context"
	"fmt"
	"time"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Create a new Lua state with security options
	L := lua.NewState(lua.Options{
		// Skip opening standard libraries that could be dangerous
		SkipOpenLibs: true,
	})
	defer L.Close()

	// Manually open only safe libraries
	// We only open base library with restrictions
	for _, pair := range []struct {
		n string
		f lua.LGFunction
	}{
		{lua.LoadLibName, lua.OpenPackage},
		{lua.BaseLibName, lua.OpenBase},
		{lua.TabLibName, lua.OpenTable},
		{lua.StringLibName, lua.OpenString},
		{lua.MathLibName, lua.OpenMath},
	} {
		if err := L.CallByParam(lua.P{
			Fn:      L.NewFunction(pair.f),
			NRet:    0,
			Protect: true,
		}, lua.LString(pair.n)); err != nil {
			return 0, fmt.Errorf("failed to open library %s: %w", pair.n, err)
		}
	}

	// Remove dangerous functions from the global environment
	dangerousFunctions := []string{
		"dofile",
		"loadfile",
		"load",
		"loadstring",
		"require",
		"module",
		"rawget",
		"rawset",
		"rawequal",
		"setmetatable",
		"getmetatable",
		"debug",
		"io",
		"os",
		"package",
	}

	for _, fn := range dangerousFunctions {
		L.SetGlobal(fn, lua.LNil)
	}

	// Set instruction limit to prevent infinite loops (10 million instructions)
	L.SetContext(context.Background())
	instructionLimit := 10000000
	L.SetMx(instructionLimit)

	// Create a channel to handle timeout
	done := make(chan error, 1)
	var result float64

	// Execute script with timeout
	go func() {
		defer func() {
			if r := recover(); r != nil {
				done <- fmt.Errorf("panic during script execution: %v", r)
			}
		}()

		// Load and execute the script
		if err := L.DoString(script); err != nil {
			done <- fmt.Errorf("failed to execute Lua script: %w", err)
			return
		}

		// Get the calculate_final_price function from global scope
		fn := L.GetGlobal("calculate_final_price")
		if fn.Type() != lua.LTFunction {
			done <- fmt.Errorf("calculate_final_price is not a function or not defined")
			return
		}

		// Convert Go context map to Lua table
		ctxTable := L.NewTable()
		for k, v := range ctx {
			L.SetField(ctxTable, k, lua.LNumber(v))
		}

		// Call the function with the context table
		if err := L.CallByParam(lua.P{
			Fn:      fn,
			NRet:    1,
			Protect: true,
		}, ctxTable); err != nil {
			done <- fmt.Errorf("failed to call calculate_final_price: %w", err)
			return
		}

		// Get the result from the Lua stack
		ret := L.Get(-1)
		L.Pop(1) // Remove the result from the stack

		// Convert result to float64
		if ret.Type() != lua.LTNumber {
			done <- fmt.Errorf("calculate_final_price did not return a number")
			return
		}

		result = float64(ret.(lua.LNumber))

		// Validate the result is not NaN or Inf
		if result != result { // NaN check
			done <- fmt.Errorf("calculate_final_price returned NaN")
			return
		}

		// Check for reasonable price bounds (prevent overflow attacks)
		if result < 0 || result > 1e15 {
			done <- fmt.Errorf("calculate_final_price returned invalid price: %f", result)
			return
		}

		done <- nil
	}()

	// Wait for execution with timeout (5 seconds)
	timeout := 5 * time.Second
	select {
	case err := <-done:
		if err != nil {
			return 0, err
		}
		return result, nil
	case <-time.After(timeout):
		return 0, fmt.Errorf("script execution timeout after %v", timeout)
	}
}

