import (
	"context"
	"fmt"
	"math"
	"time"

	lua "github.com/yuin/gopher-lua"
)

const (
	// Maximum script size in bytes (100KB)
	maxScriptSize = 100 * 1024
	// Maximum execution time
	maxExecutionTime = 2 * time.Second
	// Maximum number of Lua instructions before yielding
	maxInstructions = 100000
)

// ExecutePricingScript executes a user-provided Lua script to calculate the final price
// of a product based on the given context.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Validate script size
	if len(script) > maxScriptSize {
		return 0, fmt.Errorf("script size exceeds maximum allowed size of %d bytes", maxScriptSize)
	}

	// Validate script is not empty
	if len(script) == 0 {
		return 0, fmt.Errorf("script cannot be empty")
	}

	// Create a new Lua state with restricted options
	L := lua.NewState(lua.Options{
		CallStackSize:       120,  // Limit call stack depth
		RegistrySize:        1024, // Limit registry size
		RegistryMaxSize:     2048, // Maximum registry size
		RegistryGrowStep:    32,   // Registry growth step
		SkipOpenLibs:        true, // Skip opening all libraries by default
		IncludeGoStackTrace: false,
	})
	defer L.Close()

	// Only open safe libraries (exclude os, io, debug, package, etc.)
	// Only load base library and math library with restrictions
	openSafeLuaLibs(L)

	// Set instruction count limit to prevent infinite loops
	ctx2, cancel := context.WithTimeout(context.Background(), maxExecutionTime)
	defer cancel()

	// Set up context for timeout checking
	L.SetContext(ctx2)

	// Start a goroutine to monitor timeout
	done := make(chan bool)
	go func() {
		select {
		case <-ctx2.Done():
			L.Close()
		case <-done:
		}
	}()
	defer close(done)

	// Load and execute the script
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Validate context values
	for k, v := range ctx {
		if math.IsNaN(v) || math.IsInf(v, 0) {
			return 0, fmt.Errorf("invalid context value for key %s: NaN or Inf not allowed", k)
		}
		if v < 0 {
			return 0, fmt.Errorf("invalid context value for key %s: negative values not allowed", k)
		}
	}

	// Convert Go context map to Lua table
	ctxTable := L.NewTable()
	for k, v := range ctx {
		L.SetField(ctxTable, k, lua.LNumber(v))
	}

	// Call the function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the result from the Lua stack
	result := L.Get(-1)
	L.Pop(1) // Remove the result from the stack

	// Convert result to float64
	if result.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number")
	}

	finalPrice := float64(result.(lua.LNumber))

	// Validate the result
	if math.IsNaN(finalPrice) || math.IsInf(finalPrice, 0) {
		return 0, fmt.Errorf("invalid result: NaN or Inf not allowed")
	}

	if finalPrice < 0 {
		return 0, fmt.Errorf("invalid result: negative price not allowed")
	}

	// Reasonable upper bound check (adjust based on business requirements)
	if finalPrice > 1e12 {
		return 0, fmt.Errorf("invalid result: price exceeds reasonable maximum")
	}

	return finalPrice, nil
}

// openSafeLuaLibs opens only safe Lua libraries
func openSafeLuaLibs(L *lua.LState) {
	// Open only safe base functions
	loadSafeBase(L)

	// Open math library (generally safe)
	L.Push(L.NewFunction(lua.OpenMath))
	L.Push(lua.LString("math"))
	L.Call(1, 0)

	// Open string library (generally safe)
	L.Push(L.NewFunction(lua.OpenString))
	L.Push(lua.LString("string"))
	L.Call(1, 0)

	// Open table library (generally safe)
	L.Push(L.NewFunction(lua.OpenTable))
	L.Push(lua.LString("table"))
	L.Call(1, 0)
}

// loadSafeBase loads a restricted version of the base library
func loadSafeBase(L *lua.LState) {
	// Load base library
	L.Push(L.NewFunction(lua.OpenBase))
	L.Push(lua.LString("_G"))
	L.Call(1, 0)

	// Remove dangerous functions
	dangerousFuncs := []string{
		"dofile",    // Can read arbitrary files
		"loadfile",  // Can read arbitrary files
		"load",      // Can execute arbitrary code
		"loadstring", // Can execute arbitrary code (Lua 5.1)
		"require",   // Can load arbitrary modules
		"module",    // Module system
		"rawget",    // Can bypass metamethods
		"rawset",    // Can bypass metamethods
		"rawequal",  // Less critical but not needed
		"setfenv",   // Can modify environments (Lua 5.1)
		"getfenv",   // Can access environments (Lua 5.1)
	}

	for _, fname := range dangerousFuncs {
		L.SetGlobal(fname, lua.LNil)
	}
}

