package main

import (
	"fmt"

	lua "github.com/yuin/gopher-lua"
)

// ExecutePricingScript executes a Lua script to calculate the final price
// based on the provided context variables.
func ExecutePricingScript(script string, ctx map[string]float64) (float64, error) {
	// Initialize Lua VM
	L := lua.NewState()
	defer L.Close()

	// Execute the Lua script to define the calculate_final_price function
	if err := L.DoString(script); err != nil {
		return 0, fmt.Errorf("failed to execute Lua script: %w", err)
	}

	// Get the calculate_final_price function from Lua global scope
	fn := L.GetGlobal("calculate_final_price")
	if fn.Type() != lua.LTFunction {
		return 0, fmt.Errorf("calculate_final_price is not a function or not defined")
	}

	// Convert Go map to Lua table
	ctxTable := L.NewTable()
	for key, value := range ctx {
		L.SetField(ctxTable, key, lua.LNumber(value))
	}

	// Call the Lua function with the context table
	if err := L.CallByParam(lua.P{
		Fn:      fn,
		NRet:    1,
		Protect: true,
	}, ctxTable); err != nil {
		return 0, fmt.Errorf("failed to call calculate_final_price: %w", err)
	}

	// Get the return value from the Lua function
	ret := L.Get(-1)
	L.Pop(1)

	// Check if the return value is a number
	if ret.Type() != lua.LTNumber {
		return 0, fmt.Errorf("calculate_final_price did not return a number, got %s", ret.Type().String())
	}

	// Convert Lua number to float64
	result := float64(ret.(lua.LNumber))

	return result, nil
}

func main() {
	// Example 1: VIP user with discount
	script1 := `
function calculate_final_price(ctx)
    -- Apply 10% discount for VIP users (tier 2)
    if ctx.user_tier >= 2 then
        return ctx.base_price * 0.9
    else
        return ctx.base_price
    end
end
`
	ctx1 := map[string]float64{
		"base_price": 100.0,
		"user_tier":  2.0,
	}

	price1, err := ExecutePricingScript(script1, ctx1)
	if err != nil {
		fmt.Printf("Error executing script 1: %v\n", err)
	} else {
		fmt.Printf("Example 1 - Final price for VIP user: $%.2f\n", price1)
	}

	// Example 2: Regular user without discount
	ctx2 := map[string]float64{
		"base_price": 100.0,
		"user_tier":  1.0,
	}

	price2, err := ExecutePricingScript(script1, ctx2)
	if err != nil {
		fmt.Printf("Error executing script 2: %v\n", err)
	} else {
		fmt.Printf("Example 2 - Final price for regular user: $%.2f\n", price2)
	}

	// Example 3: Complex pricing with multiple factors
	script3 := `
function calculate_final_price(ctx)
    local price = ctx.base_price

    -- Apply tier discount
    if ctx.user_tier >= 3 then
        price = price * 0.8
    elseif ctx.user_tier >= 2 then
        price = price * 0.9
    end

    -- Apply quantity discount
    if ctx.quantity >= 10 then
        price = price * 0.95
    end

    return price * ctx.quantity
end
`
	ctx3 := map[string]float64{
		"base_price": 50.0,
		"user_tier":  3.0,
		"quantity":   12.0,
	}

	price3, err := ExecutePricingScript(script3, ctx3)
	if err != nil {
		fmt.Printf("Error executing script 3: %v\n", err)
	} else {
		fmt.Printf("Example 3 - Final price for bulk VIP order: $%.2f\n", price3)
	}

	// Example 4: Error handling - missing function
	script4 := `
function wrong_function_name(ctx)
    return ctx.base_price
end
`
	ctx4 := map[string]float64{
		"base_price": 100.0,
	}

	_, err = ExecutePricingScript(script4, ctx4)
	if err != nil {
		fmt.Printf("Example 4 - Expected error: %v\n", err)
	}
}

